import React, { useState, useEffect } from 'react';
import HandwrittenCard from '../components/HandwrittenCard';
import { 
  Calendar, ChevronLeft, ChevronRight, Star, Flag, Clock, 
  BookOpen, Search, Code, BrainCircuit, Network, 
  MessageSquareText, Database, Plus, Trash2, Edit2, Save, RotateCcw,
  CheckCircle2, AlertCircle, Lock, Unlock, X, Key
} from 'lucide-react';

interface MonthPlan {
  month: string;
  topic: string;
  details: string[];
  type: 'Topic A' | 'Topic B' | 'IA' | 'Exam' | 'Case Study' | 'Topic B4';
  isMilestone?: boolean;
}

const DEFAULT_DP1_PLAN: MonthPlan[] = [
  { month: 'August', topic: 'Course Launch & B1', type: 'Topic B', details: ['Introduction to CS', 'B1.1 Approaches to Computational Thinking'] },
  { month: 'September', topic: 'Programming B2', type: 'Topic B', details: ['Python/Java Fundamentals', 'Variables, Control Flow', 'Basic Data Structures'] },
  { month: 'October', topic: 'Algorithms B2', type: 'Topic B', details: ['Search & Sort Algorithms', 'Big O Notation', 'Trace Tables'] },
  { month: 'November', topic: 'OOP B3 Part 1', type: 'Topic B', details: ['Classes & Objects', 'Encapsulation', 'Constructors'] },
  { month: 'December', topic: 'OOP B3 Part 2', type: 'Topic B', details: ['Inheritance & Polymorphism', 'Multiple Classes Logic'] },
  { month: 'January', topic: 'Database Design A3', type: 'Topic A', details: ['A3.1 Features & Anomalies', 'A3.2.1-4 Schemas & ERDs'] },
  { month: 'February', topic: 'Normalization A3', type: 'Topic A', details: ['A3.2.5-7 1NF, 2NF, 3NF', 'Denormalization Evaluation'] },
  { month: 'March', topic: 'SQL Programming A3', type: 'Topic A', details: ['A3.3 SQL DDL & DML', 'Aggregate Functions', 'JOINS'] },
  { month: 'April', topic: 'IA Start & Review', type: 'IA', details: ['Criterion A: Problem Specification', 'Drafting success criteria'] },
  { month: 'May', topic: 'EOY Exams', type: 'Exam', isMilestone: true, details: ['Paper 1 & 2 Foundations', 'IA Criterion B Planning'] },
  { month: 'June', topic: 'IA Progress & Case Study', type: 'Case Study', isMilestone: true, details: ['CASE STUDY RELEASED!', 'Criterion B Submission'] },
];

const DEFAULT_DP1_HL_PLAN: MonthPlan[] = [
  { month: 'August', topic: 'HL Launch & B1/B2', type: 'Topic B', details: ['B1.1 Advanced Spec', 'B2.1 Fundamentals Intensive'] },
  { month: 'September', topic: 'Algorithms & Big O', type: 'Topic B', details: ['Complex Sorting', 'Big O Analysis', 'Binary Search Analysis'] },
  { month: 'October', topic: 'Recursion B2.4', type: 'Topic B', isMilestone: true, details: ['Factorials & Fibonacci', 'Tree Recursion', 'Recursion vs Iteration'] },
  { month: 'November', topic: 'Advanced OOP B3.2', type: 'Topic B', details: ['Encapsulation & Access', 'Aggregation vs Composition'] },
  { month: 'December', topic: 'Polymorphism HL', type: 'Topic B', details: ['Static Overloading', 'Dynamic Overriding', 'Abstract Classes'] },
  { month: 'January', topic: 'HL Databases A3.3', type: 'Topic A', details: ['A3.2 ERD Mastery', 'Normalization to 3NF'] },
  { month: 'February', topic: 'SQL & ACID HL', type: 'Topic A', details: ['HL Aggregates', 'ACID Transactions', 'Database Views'] },
  { month: 'March', topic: 'Data Structures HL', type: 'Topic B4', isMilestone: true, details: ['Singly & Doubly Linked Lists', 'Node Management'] },
  { month: 'April', topic: 'IA Criterion A/B', type: 'IA', details: ['Complex Problem Modeling', 'System Decomposition'] },
  { month: 'May', topic: 'EOY HL Intensive', type: 'Exam', isMilestone: true, details: ['Paper 1 & 2 HL Core', 'Mock Assessment'] },
  { month: 'June', topic: 'Case Study HL', type: 'Case Study', isMilestone: true, details: ['Case Study Research', 'IA Development Start'] },
];

const DEFAULT_DP2_PLAN: MonthPlan[] = [
  { month: 'August', topic: 'Networks A2 & IA Dev', type: 'Topic A', details: ['A2.1-2 Network Fundamentals', 'IA Criterion D: Development'] },
  { month: 'September', topic: 'Network Security A2', type: 'Topic A', details: ['A2.3-4 Security Protocols', 'Encryption Basics'] },
  { month: 'October', topic: 'IA Development Cont.', type: 'IA', details: ['Coding the Product', 'Drafting Testing Strategy'] },
  { month: 'November', topic: 'Machine Learning A4', type: 'Topic A', details: ['A4.1-3 ML Foundations', 'Supervised vs Unsupervised'] },
  { month: 'December', topic: 'Computer Fundamentals A1', type: 'Topic A', details: ['A1.1 CPU Components', 'A1.3 OS & Scheduling', 'Final IA Submission'] },
  { month: 'January', topic: 'Mock Exams', type: 'Exam', isMilestone: true, details: ['Full Past Paper Simulation', 'Case Study Deep Dive 1'] },
  { month: 'February', topic: 'Case Study & Review', type: 'Case Study', details: ['Detailed research on pre-seen', 'Linking questions practice'] },
  { month: 'March', topic: 'Final Sprint', type: 'Exam', isMilestone: true, details: ['Exam Paper Mastery', 'Revision of Topic A & B'] },
];

const DEFAULT_DP2_HL_PLAN: MonthPlan[] = [
  { month: 'August', topic: 'B4 ADTs Mastery', type: 'Topic B4', isMilestone: true, details: ['Binary Search Trees', 'In/Pre/Post Traversals'] },
  { month: 'September', topic: 'Sets & Hashing B4', type: 'Topic B4', details: ['Hashing Algorithms', 'Collision Resolution', 'Set Operations'] },
  { month: 'October', topic: 'IA HL Development', type: 'IA', details: ['Implementing ADTs in IA', 'Complex Logic Documentation'] },
  { month: 'November', topic: 'A2 Network HL', type: 'Topic A', details: ['OSI Model Layers', 'Protocol Analysis', 'Advanced Security'] },
  { month: 'December', topic: 'A1/A4 HL Finish', type: 'Topic A', details: ['ML Neural Networks', 'Scheduling Algorithms', 'IA Final Polish'] },
  { month: 'January', topic: 'Full HL Mocks', type: 'Exam', isMilestone: true, details: ['Paper 1, 2, & Case Study', 'Marking & Feedback'] },
  { month: 'February', topic: 'HL Case Study Pro', type: 'Case Study', details: ['Scenario Modeling', 'Impact of Technology HL'] },
  { month: 'March', topic: 'Ultimate Revision', type: 'Exam', isMilestone: true, details: ['HL Content Synthesis', 'Past Paper Speedrun'] },
];

const TimelineSection: React.FC = () => {
  const [activeYear, setActiveYear] = useState<'DP1' | 'DP2'>('DP1');
  const [activeTrack, setActiveTrack] = useState<'SL' | 'HL'>('SL');
  const [selectedMonth, setSelectedMonth] = useState<number>(0);
  const [isEditing, setIsEditing] = useState(false);
  const [isOwner, setIsOwner] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState(false);

  const [dp1Plan, setDp1Plan] = useState<MonthPlan[]>(DEFAULT_DP1_PLAN);
  const [dp2Plan, setDp2Plan] = useState<MonthPlan[]>(DEFAULT_DP2_PLAN);
  const [dp1HlPlan, setDp1HlPlan] = useState<MonthPlan[]>(DEFAULT_DP1_HL_PLAN);
  const [dp2HlPlan, setDp2HlPlan] = useState<MonthPlan[]>(DEFAULT_DP2_HL_PLAN);

  useEffect(() => {
    const savedDp1 = localStorage.getItem('ibdp_cs_dp1_plan');
    const savedDp2 = localStorage.getItem('ibdp_cs_dp2_plan');
    const savedDp1Hl = localStorage.getItem('ibdp_cs_dp1_hl_plan');
    const savedDp2Hl = localStorage.getItem('ibdp_cs_dp2_hl_plan');

    if (savedDp1) setDp1Plan(JSON.parse(savedDp1));
    if (savedDp2) setDp2Plan(JSON.parse(savedDp2));
    if (savedDp1Hl) setDp1HlPlan(JSON.parse(savedDp1Hl));
    if (savedDp2Hl) setDp2HlPlan(JSON.parse(savedDp2Hl));

    const ownerSession = sessionStorage.getItem('ibdp_owner_authenticated');
    if (ownerSession === 'true') {
      setIsOwner(true);
    }
  }, []);

  const getCurrentPlan = () => {
    if (activeYear === 'DP1') return activeTrack === 'SL' ? dp1Plan : dp1HlPlan;
    return activeTrack === 'SL' ? dp2Plan : dp2HlPlan;
  };

  const getSetPlan = () => {
    if (activeYear === 'DP1') return activeTrack === 'SL' ? setDp1Plan : setDp1HlPlan;
    return activeTrack === 'SL' ? setDp2Plan : setDp2HlPlan;
  };

  const currentPlan = getCurrentPlan();
  const setPlan = getSetPlan();

  // Safety check for month index
  const safeMonthIdx = Math.min(selectedMonth, currentPlan.length - 1);
  const currentItem = currentPlan[safeMonthIdx];

  const handleAuthSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === 'Arora2027') {
      setIsOwner(true);
      setIsEditing(true);
      sessionStorage.setItem('ibdp_owner_authenticated', 'true');
      setShowAuthModal(false);
      setPasswordInput('');
      setAuthError(false);
    } else {
      setAuthError(true);
    }
  };

  const toggleEditMode = () => {
    if (isOwner) {
      setIsEditing(!isEditing);
    } else {
      setShowAuthModal(true);
    }
  };

  const logoutOwner = () => {
    setIsOwner(false);
    setIsEditing(false);
    sessionStorage.removeItem('ibdp_owner_authenticated');
  };

  const saveToStorage = (p1sl: MonthPlan[], p2sl: MonthPlan[], p1hl: MonthPlan[], p2hl: MonthPlan[]) => {
    localStorage.setItem('ibdp_cs_dp1_plan', JSON.stringify(p1sl));
    localStorage.setItem('ibdp_cs_dp2_plan', JSON.stringify(p2sl));
    localStorage.setItem('ibdp_cs_dp1_hl_plan', JSON.stringify(p1hl));
    localStorage.setItem('ibdp_cs_dp2_hl_plan', JSON.stringify(p2hl));
  };

  const updateCurrentItem = (updates: Partial<MonthPlan>) => {
    if (!isOwner) return;
    const newPlan = [...currentPlan];
    newPlan[safeMonthIdx] = { ...newPlan[safeMonthIdx], ...updates };
    setPlan(newPlan);

    // Pass all 4 plans to persistence to be safe
    saveToStorage(
      activeYear === 'DP1' && activeTrack === 'SL' ? newPlan : dp1Plan,
      activeYear === 'DP2' && activeTrack === 'SL' ? newPlan : dp2Plan,
      activeYear === 'DP1' && activeTrack === 'HL' ? newPlan : dp1HlPlan,
      activeYear === 'DP2' && activeTrack === 'HL' ? newPlan : dp2HlPlan
    );
  };

  const handleAddDetail = () => {
    const newDetails = [...currentItem.details, 'New sub-topic...'];
    updateCurrentItem({ details: newDetails });
  };

  const handleRemoveDetail = (index: number) => {
    const newDetails = currentItem.details.filter((_, i) => i !== index);
    updateCurrentItem({ details: newDetails });
  };

  const handleUpdateDetail = (index: number, val: string) => {
    const newDetails = [...currentItem.details];
    newDetails[index] = val;
    updateCurrentItem({ details: newDetails });
  };

  const resetToDefault = () => {
    if (!isOwner) return;
    if (window.confirm("Reset the timeline to the standard curriculum? This will erase your custom edits for the current level/track.")) {
      if (activeYear === 'DP1') {
        if (activeTrack === 'SL') setDp1Plan(DEFAULT_DP1_PLAN);
        else setDp1HlPlan(DEFAULT_DP1_HL_PLAN);
      } else {
        if (activeTrack === 'SL') setDp2Plan(DEFAULT_DP2_PLAN);
        else setDp2HlPlan(DEFAULT_DP2_HL_PLAN);
      }
      // Re-save all to be safe
      localStorage.removeItem(`ibdp_cs_${activeYear.toLowerCase()}_${activeTrack === 'SL' ? '' : 'hl_'}plan`);
    }
  };

  const getTypeColor = (type: string) => {
    switch (type) {
      case 'Topic A': return 'bg-pink-100 text-pink-700 border-pink-200';
      case 'Topic B': return 'bg-blue-100 text-blue-700 border-blue-200';
      case 'Topic B4': return 'bg-purple-900 text-white border-purple-950';
      case 'IA': return 'bg-indigo-100 text-indigo-700 border-indigo-200';
      case 'Exam': return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case 'Case Study': return 'bg-emerald-100 text-emerald-700 border-emerald-200';
      default: return 'bg-slate-100 text-slate-700 border-slate-200';
    }
  };

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700 pb-20 relative">
      {/* Authentication Modal */}
      {showAuthModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white p-8 rounded-[2rem] sketch-border shadow-2xl max-w-sm w-full relative">
            <button 
              onClick={() => { setShowAuthModal(false); setAuthError(false); setPasswordInput(''); }} 
              className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 p-2"
            >
              <X size={20} />
            </button>
            <div className="text-center mb-6">
              <div className="w-16 h-16 bg-yellow-100 rounded-full flex items-center justify-center mx-auto mb-4 border-2 border-yellow-200 shadow-inner">
                <Key className="text-yellow-600" size={32} />
              </div>
              <h2 className="text-2xl font-black handwritten text-slate-900">Owner Mode</h2>
              <p className="text-xs kalam text-slate-500 mt-1">Enter the secret passcode to unlock curriculum editing tools.</p>
            </div>
            <form onSubmit={handleAuthSubmit} className="space-y-4">
              <div>
                <input 
                  type="password"
                  value={passwordInput}
                  onChange={(e) => { setPasswordInput(e.target.value); setAuthError(false); }}
                  placeholder="Passcode..."
                  autoFocus
                  className={`w-full px-4 py-3 bg-slate-50 border-2 rounded-xl text-center font-bold tracking-widest focus:outline-none transition-colors ${authError ? 'border-red-500 bg-red-50 text-red-600 animate-shake' : 'border-slate-200 focus:border-slate-900'}`}
                />
                {authError && <p className="text-[10px] text-red-500 font-bold mt-2 text-center uppercase tracking-tight italic">Invalid passcode. Please try again.</p>}
              </div>
              <button 
                type="submit"
                className="w-full py-3 bg-slate-900 text-white rounded-xl font-black shadow-lg hover:bg-slate-800 transition-all active:scale-95"
              >
                UNLOCK TOOLS
              </button>
            </form>
          </div>
        </div>
      )}

      <div className="text-center relative py-8">
        <div className="tape"></div>
        <h1 className="text-5xl md:text-6xl font-black handwritten text-slate-900 mb-2">Curriculum Journey</h1>
        <p className="text-xl kalam text-slate-600 italic">"The 18-month roadmap to IBDP Success"</p>

        <div className="mt-8 flex flex-col md:flex-row items-center justify-center gap-6">
          {/* Level Switcher */}
          <div className="inline-flex bg-slate-200 p-1 rounded-2xl sketch-border">
            <button 
              onClick={() => { setActiveYear('DP1'); setSelectedMonth(0); }} 
              className={`px-6 py-2 rounded-xl font-black text-xs transition-all ${activeYear === 'DP1' ? 'bg-slate-900 text-white shadow-xl scale-105' : 'text-slate-500'}`}
            >
              YEAR 1: DP1
            </button>
            <button 
              onClick={() => { setActiveYear('DP2'); setSelectedMonth(0); }} 
              className={`px-6 py-2 rounded-xl font-black text-xs transition-all ${activeYear === 'DP2' ? 'bg-slate-900 text-white shadow-xl scale-105' : 'text-slate-500'}`}
            >
              YEAR 2: DP2
            </button>
          </div>

          {/* Track Switcher */}
          <div className="inline-flex bg-purple-100 p-1 rounded-2xl sketch-border border-2 border-purple-200">
            <button 
              onClick={() => { setActiveTrack('SL'); setSelectedMonth(0); }} 
              className={`px-6 py-2 rounded-xl font-black text-xs transition-all ${activeTrack === 'SL' ? 'bg-indigo-600 text-white shadow-lg scale-105' : 'text-indigo-400'}`}
            >
              STANDARD (SL)
            </button>
            <button 
              onClick={() => { setActiveTrack('HL'); setSelectedMonth(0); }} 
              className={`px-6 py-2 rounded-xl font-black text-xs transition-all ${activeTrack === 'HL' ? 'bg-purple-800 text-white shadow-lg scale-105' : 'text-purple-400'}`}
            >
              HIGHER (HL)
            </button>
          </div>

          <div className="flex gap-2">
            <button 
              onClick={toggleEditMode}
              className={`flex items-center space-x-2 px-4 py-2 rounded-full font-black text-xs transition-all border-2 ${isEditing ? 'bg-green-600 text-white border-green-700 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'}`}
            >
              {isEditing ? (
                <><Save size={14}/><span>LOCK & SAVE</span></>
              ) : (
                <>{isOwner ? <Unlock size={14} className="text-green-500"/> : <Lock size={14} className="text-slate-400"/>}<span>{isOwner ? 'EDIT AS OWNER' : 'OWNER ONLY'}</span></>
              )}
            </button>

            {isOwner && (
              <>
                <button 
                  onClick={resetToDefault}
                  className="p-2 bg-white text-slate-400 hover:text-red-500 rounded-full border border-slate-200 transition-colors"
                  title="Reset to default"
                >
                  <RotateCcw size={16}/>
                </button>
                <button 
                  onClick={logoutOwner}
                  className="px-3 py-1 bg-red-50 text-red-400 hover:text-red-600 hover:bg-red-100 rounded-full text-[10px] font-black border border-red-100 transition-colors"
                >
                  LOGOUT
                </button>
              </>
            )}
          </div>
        </div>
      </div>

      {/* Main Interactive Timeline Component */}
      <div className="relative pt-12 pb-24">
        <div className="max-w-4xl mx-auto relative px-10">
          <div className="h-2 bg-slate-200 rounded-full w-full absolute top-1/2 -translate-y-1/2 left-0 z-0 border border-slate-300"></div>
          <div className="relative z-10 flex justify-between">
            {currentPlan.map((plan, idx) => (
              <button
                key={idx}
                onClick={() => setSelectedMonth(idx)}
                className={`relative flex flex-col items-center transition-all duration-300 group`}
              >
                <div className={`w-8 h-8 rounded-full border-4 flex items-center justify-center transition-all ${
                  selectedMonth === idx 
                    ? 'bg-slate-900 border-slate-900 scale-150 ring-4 ring-white shadow-lg' 
                    : plan.isMilestone ? 'bg-yellow-400 border-slate-900 scale-125' : 'bg-white border-slate-300 group-hover:border-slate-500'
                }`}>
                  {plan.isMilestone ? <Star size={12} fill="white" className="text-white"/> : <div className={`w-2 h-2 rounded-full ${selectedMonth === idx ? 'bg-white' : 'bg-slate-300'}`}></div>}
                </div>
                <span className={`mt-4 font-black text-[10px] uppercase tracking-tighter transition-colors ${selectedMonth === idx ? 'text-slate-900' : 'text-slate-400'}`}>
                  {plan.month.substring(0, 3)}
                </span>
                {plan.isMilestone && <Flag className="absolute -top-6 text-red-500 animate-bounce" size={14} />}
              </button>
            ))}
          </div>
        </div>

        <div className="mt-20 max-w-2xl mx-auto">
          <div className="animate-in fade-in zoom-in-95 duration-500" key={`${activeYear}-${activeTrack}-${selectedMonth}`}>
            <HandwrittenCard bgColor="bg-white" className="shadow-2xl border-4 border-slate-900 overflow-hidden min-h-[400px]">
              <div className="absolute top-0 right-0 px-6 py-2 bg-slate-900 text-white rounded-bl-3xl font-black text-xl handwritten">
                {currentItem.month}
              </div>

              <div className="flex items-center space-x-3 mb-6 pt-4">
                {isEditing ? (
                  <select 
                    value={currentItem.type}
                    onChange={(e) => updateCurrentItem({ type: e.target.value as any })}
                    className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border-2 outline-none ${getTypeColor(currentItem.type)}`}
                  >
                    <option value="Topic A">Topic A</option>
                    <option value="Topic B">Topic B</option>
                    <option value="Topic B4">Topic B4 (HL)</option>
                    <option value="IA">IA</option>
                    <option value="Exam">Exam</option>
                    <option value="Case Study">Case Study</option>
                  </select>
                ) : (
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border-2 ${getTypeColor(currentItem.type)}`}>
                    {currentItem.type}
                  </span>
                )}

                {isEditing ? (
                   <label className="flex items-center space-x-2 cursor-pointer bg-yellow-50 px-3 py-1 rounded-full border border-yellow-200">
                     <input 
                       type="checkbox" 
                       checked={currentItem.isMilestone} 
                       onChange={(e) => updateCurrentItem({ isMilestone: e.target.checked })}
                       className="w-3 h-3 accent-yellow-600"
                     />
                     <span className="text-[10px] font-black uppercase text-yellow-800">Milestone</span>
                   </label>
                ) : (
                  currentItem.isMilestone && <span className="bg-yellow-400 text-slate-900 px-3 py-1 rounded-full text-[10px] font-black uppercase border-2 border-slate-900 shadow-sm">Milestone Event</span>
                )}
              </div>

              {isEditing ? (
                <div className="mb-6">
                  <input 
                    type="text"
                    value={currentItem.topic}
                    onChange={(e) => updateCurrentItem({ topic: e.target.value })}
                    className="w-full text-3xl font-black text-slate-900 bg-slate-50 border-b-4 border-slate-900 p-2 focus:outline-none focus:bg-white"
                    placeholder="Enter month topic..."
                  />
                </div>
              ) : (
                <h2 className="text-3xl font-black text-slate-900 mb-6 flex items-center">
                  {currentItem.type === 'Exam' ? <Calendar className="mr-3 text-red-500" size={32}/> : <BookOpen className="mr-3 text-indigo-600" size={32}/>}
                  {currentItem.topic}
                </h2>
              )}

              <div className="space-y-4">
                <div className="flex items-center justify-between border-b border-slate-100 pb-1">
                  <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Key Objectives:</h4>
                  {isEditing && (
                    <button 
                      onClick={handleAddDetail}
                      className="text-[10px] font-black text-indigo-600 hover:text-indigo-800 flex items-center bg-indigo-50 px-2 py-0.5 rounded"
                    >
                      <Plus size={12} className="mr-1"/> ADD SUB-TOPIC
                    </button>
                  )}
                </div>

                <ul className="space-y-3">
                  {currentItem.details.map((detail, dIdx) => (
                    <li key={dIdx} className="group flex items-start text-sm kalam font-bold text-slate-700">
                      <div className="w-5 h-5 rounded bg-slate-100 flex items-center justify-center mr-3 mt-0.5 shrink-0 border border-slate-200">
                        <span className="text-[8px]">{dIdx + 1}</span>
                      </div>

                      {isEditing ? (
                        <div className="flex-1 flex items-center space-x-2">
                          <input 
                            type="text"
                            value={detail}
                            onChange={(e) => handleUpdateDetail(dIdx, e.target.value)}
                            className="flex-1 bg-slate-50 border-b border-slate-200 p-1 focus:outline-none focus:border-slate-900"
                          />
                          <button 
                            onClick={() => handleRemoveDetail(dIdx)}
                            className="text-slate-300 hover:text-red-500 transition-colors"
                          >
                            <Trash2 size={14}/>
                          </button>
                        </div>
                      ) : (
                        <span className="flex-1">{detail}</span>
                      )}
                    </li>
                  ))}
                  {currentItem.details.length === 0 && (
                    <p className="text-xs text-slate-400 italic py-4 text-center border-2 border-dashed border-slate-100 rounded-xl">No sub-topics added for this month.</p>
                  )}
                </ul>
              </div>

              <div className="mt-auto pt-12 flex justify-between items-end border-t border-dashed border-slate-200">
                 <div className="text-[9px] font-mono text-slate-400 uppercase tracking-widest pb-6">
                    Planner Ref: IBDP-CS-2027-{activeTrack}-V1
                 </div>
                 <div className="bg-yellow-50 p-3 sketch-border -rotate-1 group cursor-pointer mb-6" onClick={() => {}}>
                    <p className="text-[10px] kalam font-black text-slate-600 flex items-center">
                       <MessageSquareText size={12} className="mr-1 text-slate-400"/> Speak to Ms Arora
                    </p>
                 </div>
              </div>
            </HandwrittenCard>
          </div>
        </div>
      </div>

      <div className="grid lg:grid-cols-2 gap-10">
        <HandwrittenCard title="Track Overview" bgColor="bg-blue-50" className="border-blue-200">
