            <button onClick={() => { setShowAuthModal(false); setAuthError(false); setPasswordInput(''); }} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 p-2"><X size={20} /></button>
            <div className="text-center mb-6">
              <div className="w-16 h-16 bg-yellow-100 rounded-full flex items-center justify-center mx-auto mb-4 border-2 border-yellow-200 shadow-inner"><Key className="text-yellow-600" size={32} /></div>
              <h2 className="text-2xl font-black handwritten text-slate-900">Owner Mode</h2>
              <p className="text-xs kalam text-slate-500 mt-1">Enter passcode to unlock editing.</p>
            </div>
            <form onSubmit={handleAuthSubmit} className="space-y-4">
              <input type="password" value={passwordInput} onChange={(e) => { setPasswordInput(e.target.value); setAuthError(false); }} placeholder="Passcode..." autoFocus className={`w-full px-4 py-3 bg-slate-50 border-2 rounded-xl text-center font-bold tracking-widest focus:outline-none transition-colors ${authError ? 'border-red-500 bg-red-50 text-red-600 animate-shake' : 'border-slate-200 focus:border-slate-900'}`}/>
              <button type="submit" className="w-full py-3 bg-slate-900 text-white rounded-xl font-black shadow-lg hover:bg-slate-800 transition-all active:scale-95">UNLOCK TOOLS</button>
            </form>
          </div>
        </div>
      )}

      <div className="text-center relative py-8">
