              <div className={`absolute top-0 right-0 px-6 py-2 text-white rounded-bl-3xl font-black text-xl handwritten ${currentItem.type === 'Topic Assessment' ? 'bg-orange-600 animate-pulse' : 'bg-slate-900'}`}>
